head.script:
scwin.afterSaveRetrieveYN = "YES";
scwin.nowDt = "";
scwin.loginId = "";
scwin.lobranCd = "";
scwin.odrNo = "";
scwin.wrkStDt = "";
scwin.wrkEndDt = "";
scwin.cntrNo = "";
scwin.qryClsCd = "";
scwin.loUpperLobranCd = "";
scwin.PCHS_CLNT_CLS_CD_HIRECAR = "";
scwin.CARGO_CLS_CD_CONTAINER = "";
scwin.WRK_STP_CD_RETRV = "";
scwin.CNTR_WRK_KND_CD_BOBTAIL = "";
scwin.CNTR_WRK_KND_CD_ONGROUND = "";
scwin.URL_CONTAINER_WORK_PATH_DETAIL_CHANGE_POPUP = "";

scwin.hid_vehclNo = "";
scwin.hid_vehclClntNo = "";
scwin.hid_vehclClntNm = "";
scwin.hid_drvNm = "";
scwin.hid_mpNo = "";
scwin.hid_eqCd = "";
scwin.hid_pdaYn = "";
scwin.hid_chassisEqCd = "";
scwin.hid_chassisKndCd = "";
scwin.hid_chassisNo = "";
scwin.lobranCdHidden = "";

scwin.onpageload = async function() {
    scwin.nowDt = WebSquare.date.getCurrentServerDate("yyyyMMdd");
    scwin.loginId = $c.ses.getUserId();
    scwin.loUpperLobranCd = $c.ses.getLoUpperLobranCd();

    let params = $c.data.getParameter();
    scwin.lobranCd = (params && params.lobranCd) ? params.lobranCd : "";
    scwin.odrNo = (params && params.odrNo) ? params.odrNo : "";
    scwin.wrkStDt = (params && params.wrkStDt) ? params.wrkStDt : "";
    scwin.wrkEndDt = (params && params.wrkEndDt) ? params.wrkEndDt : "";
    scwin.cntrNo = (params && params.cntrNo) ? params.cntrNo : "";
    scwin.qryClsCd = (params && params.qryClsCd) ? params.qryClsCd : "";

    scwin.PCHS_CLNT_CLS_CD_HIRECAR = (params && params.PCHS_CLNT_CLS_CD_HIRECAR) ? params.PCHS_CLNT_CLS_CD_HIRECAR : "";
    scwin.CARGO_CLS_CD_CONTAINER = (params && params.CARGO_CLS_CD_CONTAINER) ? params.CARGO_CLS_CD_CONTAINER : "";
    scwin.WRK_STP_CD_RETRV = (params && params.WRK_STP_CD_RETRV) ? params.WRK_STP_CD_RETRV : "";
    scwin.CNTR_WRK_KND_CD_BOBTAIL = (params && params.CNTR_WRK_KND_CD_BOBTAIL) ? params.CNTR_WRK_KND_CD_BOBTAIL : "";
    scwin.CNTR_WRK_KND_CD_ONGROUND = (params && params.CNTR_WRK_KND_CD_ONGROUND) ? params.CNTR_WRK_KND_CD_ONGROUND : "";
    scwin.URL_CONTAINER_WORK_PATH_DETAIL_CHANGE_POPUP = (params && params.URL_CONTAINER_WORK_PATH_DETAIL_CHANGE_POPUP) ? params.URL_CONTAINER_WORK_PATH_DETAIL_CHANGE_POPUP : "";
};

scwin.onUdcCompleted = async function() {
    if (scwin.wrkStDt == "") {
        udc_dptIntendDd.setInitDate(scwin.nowDt, scwin.nowDt);
    } else {
        udc_dptIntendDd.setInitDate(scwin.wrkStDt, scwin.wrkEndDt);
    }

    if (scwin.lobranCd == "") {
        acb_lobranCd.setValue(scwin.loUpperLobranCd);
        acb_vehclLobranCd.setValue(scwin.loUpperLobranCd);
    } else {
        acb_lobranCd.setValue(scwin.lobranCd);
        acb_vehclLobranCd.setValue(scwin.lobranCd);
    }

    if (scwin.qryClsCd != "") {
        acb_qryClsCd.setValue(scwin.qryClsCd);
    } else {
        acb_qryClsCd.setValue("N");
    }

    if (scwin.cntrNo != "") {
        acb_noClsCd.setValue("C");
        em_cntrOdrNo.setValue(scwin.cntrNo);
        scwin.f_Retrieve();
    } else if (scwin.odrNo != "") {
        acb_noClsCd.setValue("O");
        em_cntrOdrNo.setValue(scwin.odrNo);
        scwin.f_Retrieve();
    } else {
        acb_noClsCd.setValue("O");
    }

    chk_retrvStpYn.setValue("true");
};

scwin.f_Retrieve = async function() {
    if (acb_noClsCd.getValue() == "C") {
        let cntrOdrNo = em_cntrOdrNo.getValue();
        if ($c.gus.cfGetByteLength(cntrOdrNo) != 11) {
            await $c.win.alert("컨테이너 번호 11자리를 입력해주세요.");
            return;
        }
    }

    if (!$c.gus.cfIsAfterDate(ica_dptIntendDd.getValue(), ica_dptIntendDd2.getValue())) {
        await $c.gus.cfAlertMsg(MSG_CM_ERR_039);
        ica_dptIntendDd.setFocus();
        return;
    }

    if (acb_lobranCd.getValue() == "4BB"
        && scwin.loUpperLobranCd == "4BB"
        && scwin.loginId != "111897"
        && scwin.loginId != "150054"
        && scwin.loginId != "180023"
        && scwin.loginId != "210269"
        && scwin.loginId != "223166"
        && scwin.loginId != "223035"
        && scwin.loginId != "223033"
        && scwin.loginId != "223203"
        && scwin.loginId != "210269"
    ) {
        await $c.win.alert("조회 불가 합니다. 배차지시 화면을 이용하세요.");
        return;
    }

    ds_search.set("realMchtClntNo", em_realMchtClntNo.getValue());
    ds_search.set("stDt", ica_dptIntendDd.getValue());
    ds_search.set("endDt", ica_dptIntendDd2.getValue());
    ds_search.set("dptIntendDd", ica_dptIntendDd.getValue());
    ds_search.set("dptIntendDd2", ica_dptIntendDd2.getValue());
    ds_search.set("alloccarPicId", em_alloccarPicId.getValue());
    ds_search.set("vehclClntNo", em_vehclClntNo.getValue());
    ds_search.set("cntrOdrNo", em_cntrOdrNo.getValue());

    await $c.sbm.execute(sbm_retrieve);
};

scwin.f_RetrieveVechl = async function() {
    let activeIdx = mxTab.getSelectedTabIndex();
    if (activeIdx == 1) {
        await $c.sbm.execute(sbm_retrieveVehcl);
    } else if (activeIdx == 0) {
        if (acb_vehclLobranCd.getValue() == "") {
            await $c.win.alert("점소를 선택하세요.");
            acb_vehclLobranCd.setFocus();
            return;
        } else if (ica_dptIntendDd.getValue() == "") {
            await $c.win.alert("출발예정일을 입력하세요.");
            ica_dptIntendDd.setFocus();
            return;
        }
        scwin.f_RetrieveSuitableVehcl();
    } else if (activeIdx == 2) {
        if (!await $c.gus.cfValidate([tb_vehclCond])) return;
        if (!$c.gus.cfIsAfterDate(ica_dptIntendDd.getValue(), ica_dptIntendDd2.getValue())) {
            await $c.gus.cfAlertMsg(MSG_CM_ERR_039);
            ica_dptIntendDd.setFocus();
            return;
        }
        ds_search.set("cntrBulkGubun", "C");
        await $c.sbm.execute(sbm_memberVehicleOwnerListRetrieve);
    } else if (activeIdx == 3) {
        await $c.sbm.execute(sbm_retrieveTransBP);
    } else if (activeIdx == 4) {
        if (!await $c.gus.cfValidate([tb_vehclCond])) return;
        await $c.sbm.execute(sbm_retrieveTransBPShpmnt);
    }
};

scwin.f_RetrieveSuitableVehcl = async function() {
    let row = ds_results.getRowPosition();
    ds_vehclSearch.set("wrkLobranCd", ds_results.getCellData(row, "wrkLobranCd"));
    ds_vehclSearch.set("dptWrkPlCd", ds_results.getCellData(row, "dptWrkPlCd"));
    ds_vehclSearch.set("wrkStDt", ds_results.getCellData(row, "wrkStDt"));

    ds_results.sort("odrNo", "asc");

    await $c.sbm.execute(sbm_retrieveSutableVehcl);
};

scwin.f_Save = async function(retrieveYn) {
    let preChecked = (chk_retrvStpYn.getValue() == "true");
    if (preChecked) {
        chk_retrvStpYn.setValue("false");
        scwin.f_filter();
    }

    if (!ds_results.isUpdated()) {
        await $c.win.alert("변경된 사항이 없습니다.");
        return;
    }

    for (let i = 0; i < ds_results.getRowCount(); i++) {
        if (ds_results.getCellData(i, "vehclClntNo") == ds_results.getCellData(i, "bilgClntNo")) {
            await $c.win.alert("오더의 청구거래처와 협력 운송업체가 동일한 경우 저장 할 수 없습니다.");
            return false;
        }
    }

    if (acb_qryClsCd.getValue() == "N") {
        for (let i = 0; i < ds_results.getRowCount(); i++) {
            if (ds_results.getRowStatus(i) == "U") {
                if (ds_results.getCellData(i, "cntrWrkShapeCd") != "") {
                    if (ds_results.getCellData(i, "wrkStpCd") == "0002") {
                        if (i + 1 < ds_results.getRowCount() && ds_results.getCellData(i + 1, "wrkStpCd") == "0003" && ds_results.getCellData(i + 1, "vehclNo") != "") {
                            if (ds_results.getCellData(i, "odrNo") == ds_results.getCellData(i + 1, "odrNo") && ds_results.getCellData(i, "cntrSeq") == ds_results.getCellData(i + 1, "cntrSeq")) {
                                await $c.win.alert("DOOR운송 배차시, BOBTAIL, ON-GROUND를 선택하고 배차할 때는 회수단계는 차량이 없어야 합니다.");
                                ds_results.setCellData(i + 1, "vehclNo", "");
                                ds_results.setCellData(i + 1, "vehclShortNo", "");
                                return false;
                            }
                        }
                    } else if (ds_results.getCellData(i, "wrkStpCd") == "0003") {
                        if (i - 1 >= 0 && ds_results.getCellData(i - 1, "wrkStpCd") == "0002" && ds_results.getCellData(i - 1, "vehclNo") != "") {
                            if (ds_results.getCellData(i, "odrNo") == ds_results.getCellData(i - 1, "odrNo") && ds_results.getCellData(i, "cntrSeq") == ds_results.getCellData(i - 1, "cntrSeq")) {
                                await $c.win.alert("DOOR회수 배차시, BOBTAIL, ON-GROUND를 선택하고 운송단계보다 먼저 배차할 수 없습니다.");
                                ds_results.setCellData(i - 1, "vehclNo", "");
                                ds_results.setCellData(i - 1, "vehclShortNo", "");
                                ds_results.setCellData(i, "vehclNo", "");
                                ds_results.setCellData(i, "vehclShortNo", "");
                                return false;
                            }
                        }
                    } else if (ds_results.getCellData(i, "wrkStpCd") == "0047") {
                        await $c.win.alert("육송 단계는 BOBTAIL, ON-GROUND로 배차할 수 없습니다");
                        return false;
                    }
                }
                if (Number(ds_results.getCellData(i, "dcScAmt")) > 0) {
                    if (ds_results.getCellData(i, "dcScNm") == "") {
                        await $c.win.alert("할인할증금액은 팝업을 띄워서 할인할증항목을 선택하고, 금액을 입력한 후, 저장하셔야 합니다");
                        return false;
                    }
                }
            }
        }
    }

    if (acb_qryClsCd.getValue() == "Y") {
        for (let i = 0; i < ds_results.getRowCount(); i++) {
            if (ds_results.getRowStatus(i) == "U") {
                if (ds_results.getCellData(i, "cooperatorYn") == 1) {
                    if (ds_results.getCellData(i, "vehclNo") != "") {
                        await $c.win.alert("컨테이너 " + ds_results.getCellData(i, "cntrNo") + " 는 협력업체에서 이미 배차한 물량은 취소할 수 없습니다. \n협력업체에서 먼저 배차를 취소한 후 취소할 수 있습니다.");
                        return false;
                    }
                }
            }
        }
    }

    scwin.afterSaveRetrieveYN = retrieveYn;
    await $c.sbm.execute(sbm_save);

    if (preChecked) {
        chk_retrvStpYn.setValue("true");
        scwin.f_filter();
    }
};

scwin.f_chkOpenCommonPopUp = async function(inObj, pairObj, disGubun, isCode) {
    if (!$c.gus.cfCanOpenPopup(inObj, pairObj)) return;
    $c.gus.cfClearPairObj(pairObj);
    let pVal = $c.gus.cfGetValue(inObj);
    if (isCode == null || isCode == true)
        scwin.f_openCommonPopUp(disGubun, pVal, '', 'T', 'T');
    else
        scwin.f_openCommonPopUp(disGubun, '', pVal, 'T', 'T');
};

scwin.f_openCommonPopUp = async function(disGubun, pCode, pName, pClose, pAllSearch) {
    let rtnList;
    switch (disGubun) {
        case 4:
            rtnList = $c.gus.cfCommonPopUp('retrieveCarKindCoClntInfo_tpro', pCode, pName, pClose, null, null, null, null, scwin.PCHS_CLNT_CLS_CD_HIRECAR, null, null, null, null, null, pAllSearch, "협력업체,협력업체코드/명,");
            $c.gus.cfSetReturnValue(rtnList, em_clntNo, txt_clntNm);
            break;
        case 5:
            rtnList = $c.gus.cfCommonPopUp('retrieveUserInfo_tpro', pCode, pName, pClose, null, null, null, null, null, null, null, null, null, null, pAllSearch, null);
            $c.gus.cfSetReturnValue(rtnList, em_alloccarPicId, txt_alloccarPicNm);
            break;
        case 7:
            rtnList = $c.gus.cfCommonPopUp('retrieveChassisNo_tpro', pCode, pName, pClose, null, null, null, null, 'C', null, null, null, null, null, 'F', null);
            $c.gus.cfSetReturnValue(rtnList, em_shortChassNo, scwin.hid_chassisNo);
            scwin.hid_chassisEqCd = rtnList[4];
            scwin.hid_chassisKndCd = rtnList[2];
            break;
        case 8:
            rtnList = $c.gus.cfCommonPopUp('retrieveCarKindCoClntInfo_tpro', pCode, pName, pClose, null, null, null, null, scwin.PCHS_CLNT_CLS_CD_HIRECAR, null, null, null, null, null, pAllSearch, "협력업체,협력업체코드/명,");
            $c.gus.cfSetReturnValue(rtnList, em_vehclClntNo, txt_vehclClntNm);
            break;
        case 9:
            rtnList = $c.gus.cfCommonPopUp('retrieveBilgMchtList_tpro', pCode, pName, pClose, null, null, null, null, scwin.PCHS_CLNT_CLS_CD_HIRECAR, null, null, null, null, null, pAllSearch, "청구화주,청구화주코드/명,");
            $c.gus.cfSetReturnValue(rtnList, em_realMchtClntNo, txt_realMchtClntNm);
            break;
        default:
            break;
    }
};

scwin.f_openCommPopUpGrid = async function(disGubun, row, pClose) {
    let rtnList;
    let pCode = "";
    let pName = "";
    switch (disGubun) {
        case 2:
            pCode = ds_results.getCellData(row, "chassShortNo");
            rtnList = $c.gus.cfCommonPopUp('retrieveChassisNo_tpro', pCode, pName, pClose, null, null, null, null, 'C', null, null, null, null, null, 'F', null);
            $c.gus.cfSetGridReturnValue(rtnList, ds_results, row, "chassShortNo", "");
            ds_results.setCellData(row, "chassisEqCd", rtnList[4]);
            ds_results.setCellData(row, "chassisKndCd", rtnList[2]);
            ds_results.setCellData(row, "chassisVehclNo", rtnList[1]);

            scwin.f_checkChasisNo(row);

            let vOdrNo = ds_results.getCellData(row, "odrNo");
            let vCntrSeq = ds_results.getCellData(row, "cntrSeq");
            let vChassisEqCd = ds_results.getCellData(row, "chassisEqCd");
            let vChassisKndCd = ds_results.getCellData(row, "chassisKndCd");
            let vChassShortNo = ds_results.getCellData(row, "chassShortNo");
            let vChassisVehclNo = ds_results.getCellData(row, "chassisVehclNo");

            for (let i = 0; i < ds_results.getRowCount(); i++) {
                if (vOdrNo == ds_results.getCellData(i, "odrNo") && vCntrSeq == ds_results.getCellData(i, "cntrSeq")) {
                    ds_results.setCellData(i, "chassisEqCd", vChassisEqCd);
                    ds_results.setCellData(i, "chassisKndCd", vChassisKndCd);
                    ds_results.setCellData(i, "chassShortNo", vChassShortNo);
                    ds_results.setCellData(i, "chassisVehclNo", vChassisVehclNo);
                }
            }

            // TODO: sbm_retrieveChassis dynamic action
            break;
        default:
            break;
    }
};

scwin.f_runExcel = async function(varGrNm) {
    let totCnt = ds_results.getRowCount();
    let sheetTitle = "컨테이너운송지시";
    if (totCnt != 0) {
        let cfrm = await $c.win.confirm("EXCEL로 다운로드 받으시겠습니까?");
        if (cfrm) {
            $c.data.downloadGridViewExcel(varGrNm, { fileName: sheetTitle + ".xlsx", sheetName: sheetTitle });
        }
    } else {
        await $c.gus.cfAlertMsg(MSG_CM_WRN_002);
    }
};

scwin.f_filter = async function() {
    // TODO: ds_results.filter() — WebSquare filter API 적용 필요
    ds_results.filter();
};

scwin.f_print = async function(gubun) {
    let v_msg = "";
    if (ds_results.getRowCount() == 0 || ds_results.getRowPosition() < 0) {
        await $c.gus.cfAlertMsg(MSG_CM_ERR_056, ["오더"]);
        return;
    } else {
        let row = ds_results.getRowPosition();
        let v_lobranCd = acb_lobranCd.getValue();
        let v_odrNo = ds_results.getCellData(row, "odrNo");
        let v_cntrSeq = ds_results.getCellData(row, "cntrSeq");
        let v_cntrNo = ds_results.getCellData(row, "cntrNo");
        let v_cargoClsCd = "C";
        let v_wrkStDt = ds_results.getCellData(row, "wrkStDt");
        let v_wrkEndDt = ds_results.getCellData(row, "wrkEndDt");
        let v_dptWrkPlCd = ds_results.getCellData(row, "dptWrkPlCd");
        let v_crryinoutIntendNo = ds_results.getCellData(row, "crryinoutIntendNo");

        switch (gubun) {
            case 1:
                if ($c.gus.cfIsNull(v_odrNo)) {
                    await $c.gus.cfAlertMsg("오더를 선택하십시요");
                    return;
                }
                ds_odrSheet.set("odrNo", ds_results.getCellData(row, "odrNo"));
                ds_odrSheet.set("prtPicId", scwin.loginId);
                await $c.sbm.execute(sbm_saveOrdersheet);
                // TODO: OZ Report 호출 (op_202_02_03r)
                break;
            case 2:
                // TODO: OZ Report 호출 (op_301_01_05r)
                break;
            case 4:
                let checkCnt = 0;
                for (let i = 0; i < ds_results.getRowCount(); i++) {
                    if (scwin.f_IsSelected(i)) {
                        checkCnt++;
                    }
                }
                if (checkCnt == 0) {
                    await $c.gus.cfAlertMsg("일괄 발행할 오더를 선택하십시요.");
                    return;
                }
                // TODO: OZ Batch Print 호출
                break;
            default:
                break;
        }
    }
};

scwin.f_saveContainerCompositeCargoLinkInformation = async function() {
    ds_srch3.undo();
    let dsSeq = 0;
    let writtenCnt = 0;
    for (let i = 0; i < ds_results.getRowCount(); i++) {
        if (ds_results.getCellData(i, "combine") == 1) {
            if (ds_results.getCellData(i, "cntrSizCd") != 20) {
                await $c.win.alert("Combine은 20feet 컨테이너만 가능합니다");
                ds_results.undoAll();
                return false;
            }
            if (dsSeq == 0) {
                dsSeq = dsSeq + 1;
                ds_srch3.set("lobranCd", acb_lobranCd.getValue());
                ds_srch3.set("selOdrNo", ds_results.getCellData(i, "odrNo"));
                ds_srch3.set("selCntrSeq", ds_results.getCellData(i, "cntrSeq"));
                ds_srch3.set("selWrkStpCd", ds_results.getCellData(i, "wrkStpCd"));
                ds_srch3.set("combYn", 1);
                writtenCnt++;
            } else {
                ds_srch3.set("selOdrNo2", ds_results.getCellData(i, "odrNo"));
                ds_srch3.set("selCntrSeq2", ds_results.getCellData(i, "cntrSeq"));
                ds_srch3.set("selWrkStpCd2", ds_results.getCellData(i, "wrkStpCd"));
                writtenCnt++;
            }
            if (writtenCnt > 2) {
                await $c.win.alert("combine은 2개만 선택해야 합니다");
                ds_results.undoAll();
                return false;
            }
        }
    }
    if (writtenCnt == 1 || writtenCnt == 0) {
        await $c.win.alert("선택 개수 오류입니다. combine은 2개 선택해야 합니다");
        ds_results.undoAll();
        return false;
    }
    let chk = await $c.gus.cfConfirmMsg(MSG_CM_CRM_001);
    if (chk) {
        await $c.sbm.execute(sbm_containerCompositeCargoLink);
        scwin.f_Retrieve();
    }
};

scwin.dataSetDebug = async function(dataList, isDebug) {
    if (isDebug == true) {
        let str = "[[[[" + dataList.getID() + "]]]]]\n";
        for (let dsRow = 0; dsRow < dataList.getRowCount(); dsRow++) {
            let colCount = dataList.getColumnCount();
            for (let dsCol = 0; dsCol < colCount; dsCol++) {
                let colId = dataList.getColumnID(dsCol);
                str += "[" + colId + "] " + dataList.getCellData(dsRow, colId) + ", ";
            }
            str += "\n\n";
        }
        await $c.win.alert(str);
    }
};

scwin.f_deleteRow = async function() {
    let row = ds_results.getRowPosition();
    ds_results.undoRow(row);
    if (acb_qryClsCd.getValue() == "Y") {
        let preChecked = (chk_retrvStpYn.getValue() == "true");
        if (preChecked) {
            chk_retrvStpYn.setValue("false");
            scwin.f_filter();
        }
        let unCheckedRow = ds_results.getRowPosition();
        for (let i = 0; i < ds_results.getRowCount(); i++) {
            if (ds_results.getCellData(unCheckedRow, "transWrkIndictNo") == ds_results.getCellData(i, "transWrkIndictNo")) {
                if (acb_qryClsCd.getValue() == "Y") {
                    if (ds_results.getCellData(i, "cooperatorYn") == 0) {
                        ds_results.setCellData(i, "vehclNo", "");
                        ds_results.setCellData(i, "vehclShortNo", "");
                    } else {
                        ds_results.setCellData(i, "vehclClntNo", "");
                        ds_results.setCellData(i, "vehclShortNo", "");
                    }
                }
            }
        }
        if (preChecked) {
            chk_retrvStpYn.setValue("true");
            scwin.f_filter();
        }
    }
};

scwin.f_setVehclClntNoToChecked = async function() {
    if (em_clntNo.getValue() == "") {
        await $c.win.alert("협력업체를 선택하여 주십시오");
        em_clntNo.setFocus();
        return false;
    }
    for (let i = 0; i < ds_results.getRowCount(); i++) {
        if (ds_results.getCellData(i, "chk") == 1 && ds_results.getCellData(i, "vehclNo") == "") {
            ds_results.setCellData(i, "vehclClntNo", em_clntNo.getValue());
            ds_results.setCellData(i, "vehclClntNm", txt_clntNm.getValue());

            let v_odrNo = ds_results.getCellData(i, "odrNo");
            let v_cntrSeq = ds_results.getCellData(i, "cntrSeq");
            let v_vehclClntNo = ds_results.getCellData(i, "vehclClntNo");

            for (let j = 0; j < ds_results.getRowCount(); j++) {
                if (ds_results.getCellData(j, "vehclClntNo") != ""
                    && i != j
                    && v_odrNo == ds_results.getCellData(j, "odrNo")
                    && v_cntrSeq == ds_results.getCellData(j, "cntrSeq")
                    && v_vehclClntNo != ds_results.getCellData(j, "vehclClntNo")) {
                    await $c.win.alert("같은 오더, 컨테이너에 운송단계를 각각 다른  협력업체로 지정하여 동시에 배차할 수 없습니다. \n 운송단계 배차한 후에 회수단계를 배차하여 주시기 바랍니다.");
                    ds_results.setCellData(i, "vehclClntNo", "");
                    ds_results.setCellData(i, "vehclClntNm", "");
                    ds_results.setCellData(i, "chk", 0);
                    return false;
                }
            }
        }
    }
};

scwin.f_setVehclNoAndChassisToChecked = async function() {
    if (em_shortVhclNo.getValue() == "" && em_shortChassNo.getValue() == "") {
        await $c.win.alert("차량이나 샤시를 선택하여 주십시오");
        em_shortVhclNo.setFocus();
        return false;
    }
    let chkCnt = 0;
