scwin.f_dcScSearch = async function() {
    ds_dcScCd.removeAll();
    let row = ds_results.getRowPosition();
    let v_cargoClsCd = scwin.CARGO_CLS_CD_CONTAINER;
    let v_odrNo = ds_results.getCellData(row, "odrNo");
    let v_cntrSeq = ds_results.getCellData(row, "cntrSeq");
    let v_odrWrkPathSeq = ds_results.getCellData(row, "odrWrkPathSeq");
    let v_odrWrkStpSeq = ds_results.getCellData(row, "odrWrkStpSeq");
    let v_transWrkIndictNo = ds_results.getCellData(row, "transWrkIndictNo");
    let v_transRsltsSeq = ds_results.getCellData(row, "transRsltsSeq");
    let v_cntrNo = ds_results.getCellData(row, "cntrNo");
    let v_pchsAmt = ds_results.getCellData(row, "pchsAmt");

    let v_paramObject = {
        cargoClsCd: v_cargoClsCd,
        odrNo: v_odrNo,
        cntrSeq: v_cntrSeq,
        odrWrkPathSeq: v_odrWrkPathSeq,
        odrWrkStpSeq: v_odrWrkStpSeq,
        transWrkIndictNo: v_transWrkIndictNo,
        transRsltsSeq: v_transRsltsSeq,
        cntrNo: v_cntrNo,
        pchsAmt: v_pchsAmt
    };

    let v_URL = '/ui/ds/op/wrkplan/transwrkplan/op_202_02_12p.xml';
    await $c.win.openPopup(v_URL, { width: 400, height: 500, modal: true, data: v_paramObject });

    ds_results.setCellData(row, "dcScNm", "");
    let vSumDcScAmt = 0;
    let vDcScNm = "";
    let vDcScCd = "";

    for (let i = 0; i < ds_dcScCd.getRowCount(); i++) {
        if (v_odrNo == ds_dcScCd.getCellData(i, "odrNo")
            && v_cntrSeq == ds_dcScCd.getCellData(i, "cntrSeq")
            && v_odrWrkPathSeq == ds_dcScCd.getCellData(i, "odrWrkPathSeq")
            && v_odrWrkStpSeq == ds_dcScCd.getCellData(i, "odrWrkStpSeq")
            && v_transWrkIndictNo == ds_dcScCd.getCellData(i, "transWrkIndictNo")
            && v_transRsltsSeq == ds_dcScCd.getCellData(i, "transRsltsSeq")) {
            if ($c.gus.cfIsNull(vDcScNm)) {
                vDcScNm = ds_dcScCd.getCellData(i, "dcScNm");
                vDcScCd = ds_dcScCd.getCellData(i, "dcScCd");
            }
            vSumDcScAmt += Number(ds_dcScCd.getCellData(i, "dcScAmt"));
        }
    }
    ds_results.setCellData(row, "dcScNm", vDcScNm);
    ds_results.setCellData(row, "dcScAmt", vSumDcScAmt);
    ds_results.setCellData(row, "dcScCd", vDcScCd);
    return false;
};

