scwin.f_switchTabMenu = async function() {
    let row = ds_results.getRowPosition();
    let crryInOutCls = "";
    let v_odrNo = ds_results.getCellData(row, "odrNo");
    let v_cntrNo = ds_results.getCellData(row, "cntrNo");
    let v_wrkPlCd = "";
    let v_wrkPlNm = "";
    let v_url = "";

    if (ds_results.getCellData(row, "wrkStpCd") == "0002") {
        if (ds_results.getCellData(row, "dptWrkPlClsCd") != "C") {
            crryInOutCls = "NO";
        } else {
            crryInOutCls = "OUT";
        }
        v_wrkPlCd = ds_results.getCellData(row, "dptWrkPlCd");
        v_wrkPlNm = ds_results.getCellData(row, "dptWrkPlNm");
    } else if (ds_results.getCellData(row, "wrkStpCd") == "0003") {
        if (ds_results.getCellData(row, "arvWrkPlClsCd") != "C") {
            crryInOutCls = "NO";
        } else {
            crryInOutCls = "IN";
        }
        v_wrkPlCd = ds_results.getCellData(row, "arvWrkPlCd");
        v_wrkPlNm = ds_results.getCellData(row, "arvWrkPlNm");
    } else {
        if (ds_results.getCellData(row, "dptWrkPlClsCd") == "C") {
            crryInOutCls = "OUT";
            v_wrkPlCd = ds_results.getCellData(row, "dptWrkPlCd");
            v_wrkPlNm = ds_results.getCellData(row, "dptWrkPlNm");
        } else if (ds_results.getCellData(row, "arvWrkPlClsCd") == "C") {
            crryInOutCls = "IN";
            v_wrkPlCd = ds_results.getCellData(row, "arvWrkPlCd");
            v_wrkPlNm = ds_results.getCellData(row, "arvWrkPlNm");
        } else {
            crryInOutCls = "NO";
            v_wrkPlCd = ds_results.getCellData(row, "dptWrkPlCd");
            v_wrkPlNm = ds_results.getCellData(row, "dptWrkPlNm");
        }
    }

    if (crryInOutCls == "OUT") {
        let param = { odrNo: v_odrNo, wrkPlCd: v_wrkPlCd, cntrNo: v_cntrNo };
        $c.win.openMenu("반출등록", "/ui/ds/op/wrkrslts/cywrkrslts/op_301_01_06b.xml", "op_301_01_06b.xml", param);
    } else if (crryInOutCls == "IN") {
        let param = { odrNo: v_odrNo, wrkPlCd: v_wrkPlCd, cntrNo: v_cntrNo };
        $c.win.openMenu("반입등록", "/ui/ds/op/wrkrslts/cywrkrslts/op_301_01_05b.xml", "op_301_01_05b.xml", param);
    } else {
        let v_msg = "[오더번호 : " + v_odrNo + " , 작업장 : " + v_wrkPlNm + "] \n" + "반출입등록을 할 수 없는 오더입니다";
        await $c.gus.cfAlertMsg(v_msg);
        return;
    }
};

