scwin.f_crryInOutEDI = async function(bAlertFlag, bSaveFlag, bTransferFlag, row, bDeleteFlag) {
    if (ds_results.getRowCount() == 0) return;
    if (ds_results.getCellData(row, "vehclNo") == "") {
        await $c.gus.cfAlertMsg("운송차량이 없습니다");
        return false;
    }
    if (ds_results.getCellData(row, "crryinEdiFlag") == "N" && ds_results.getCellData(row, "crryoutEdiFlag") == "N") {
        await $c.gus.cfAlertMsg("EDI등록 대상이 아닙니다");
        return false;
    }
    if ((ds_results.getCellData(row, "crryoutEdiType") != "CO" && ds_results.getCellData(row, "crryoutEdiType") != "CD")
        && (ds_results.getCellData(row, "crryinEdiType") != "CO" && ds_results.getCellData(row, "crryinEdiType") != "CD")) {
        await $c.gus.cfAlertMsg("EDI등록 대상이 아닙니다");
        return false;
    }
    if (ds_results.getCellData(row, "emcCoreorYn") == "N") {
        await $c.gus.cfAlertMsg("선사 COREOR 없이는 EDI 전송 불가합니다.");
        return false;
    }

    if (bSaveFlag) {
        ds_searchEDI.set("qryClsCd", "");
        ds_searchEDI.set("transWrkIndictNo", ds_results.getCellData(row, "transWrkIndictNo"));
        ds_searchEDI.set("odrNo", ds_results.getCellData(row, "odrNo"));
        ds_searchEDI.set("cntrSeq", ds_results.getCellData(row, "cntrSeq"));
        ds_searchEDI.set("wrkPathSeq", ds_results.getCellData(row, "odrWrkPathSeq"));
        ds_searchEDI.set("wrkStpSeq", ds_results.getCellData(row, "odrWrkStpSeq"));
        ds_searchEDI.set("vehclNo", ds_results.getCellData(row, "vehclNo"));
        ds_searchEDI.set("crryoutDt", ds_results.getCellData(row, "wrkStDt"));
        ds_searchEDI.set("crryinDt", ds_results.getCellData(row, "wrkEndDt"));
        ds_searchEDI.set("cntrNo", ds_results.getCellData(row, "cntrNo"));
        ds_searchEDI.set("dptWrkPlCd", ds_results.getCellData(row, "dptWrkPlCd"));
        ds_searchEDI.set("arvWrkPlCd", ds_results.getCellData(row, "arvWrkPlCd"));
        ds_searchEDI.set("crryoutEdiType", ds_results.getCellData(row, "crryoutEdiType"));
        ds_searchEDI.set("crryinEdiType", ds_results.getCellData(row, "crryinEdiType"));
        ds_searchEDI.set("sndFlag", (bTransferFlag == true ? "1" : "0"));
        ds_searchEDI.set("delFlag", (bDeleteFlag == true ? "1" : "0"));
        await $c.sbm.execute(sbm_saveEDI);
        return true;
    }

    let obj = {
        qryClsCd: "",
        transWrkIndictNo: ds_results.getCellData(row, "transWrkIndictNo"),
        odrNo: ds_results.getCellData(row, "odrNo"),
        cntrSeq: ds_results.getCellData(row, "cntrSeq"),
        odrWrkPathSeq: ds_results.getCellData(row, "odrWrkPathSeq"),
        odrWrkStpSeq: ds_results.getCellData(row, "odrWrkStpSeq"),
        vehclShortNo: ds_results.getCellData(row, "vehclShortNo"),
        vehclNo: ds_results.getCellData(row, "vehclNo"),
        vehclIdCardNo: ds_results.getCellData(row, "vehclIdCardNo"),
        wrkStDt: ds_results.getCellData(row, "wrkStDt"),
        wrkEndDt: ds_results.getCellData(row, "wrkEndDt"),
        cntrNo: ds_results.getCellData(row, "cntrNo"),
        dptWrkPlCd: ds_results.getCellData(row, "dptWrkPlCd"),
        arvWrkPlCd: ds_results.getCellData(row, "arvWrkPlCd"),
        dptWrkPlNm: ds_results.getCellData(row, "dptWrkPlNm"),
        arvWrkPlNm: ds_results.getCellData(row, "arvWrkPlNm"),
        crryoutEdiType: ds_results.getCellData(row, "crryoutEdiType"),
        crryinEdiType: ds_results.getCellData(row, "crryinEdiType")
    };
