scwin.gr_results_oncellclick = async function(rowIndex, columnIndex, columnId) {
    if (columnId == "combine") {
        if (ds_results.getCellData(rowIndex, "combine") == 1) {
            if (ds_results.getCellData(rowIndex, "cmpstcrgNo") != "") {
                await $c.win.alert("컨테이너" + ds_results.getCellData(rowIndex, "cntrNo") + "는 이미 combine된 컨테이너입니다.");
                ds_results.undoRow(rowIndex);
                return false;
            }
        }
    }

    let v_odrNo = ds_results.getCellData(rowIndex, "odrNo");
    let v_cntrSeq = ds_results.getCellData(rowIndex, "cntrSeq");
    let v_chk = ds_results.getCellData(rowIndex, "chk");

    if ("0047" != ds_results.getCellData(rowIndex, "wrkStpCd")) {
        for (let i = 0; i < ds_results.getRowCount(); i++) {
            if (i != rowIndex
                && v_odrNo == ds_results.getCellData(i, "odrNo")
                && v_cntrSeq == ds_results.getCellData(i, "cntrSeq")
                && "0047" != ds_results.getCellData(i, "wrkStpCd")) {
                ds_results.setCellData(i, "chk", v_chk);
            }
        }
    }
};

