scwin.gr_transBP_oncelldblclick = async function(rowIndex, columnIndex, columnId) {
    let preChecked = (chk_retrvStpYn.getValue() == "true");
    if (preChecked) {
        chk_retrvStpYn.setValue("false");
        scwin.f_filter();
    }

    let v_row = ds_results.getRowPosition();
    ds_results.setCellData(v_row, "vehclClntNo", ds_transBP.getCellData(rowIndex, "vehclClntNo"));
    ds_results.setCellData(v_row, "vehclClntNm", ds_transBP.getCellData(rowIndex, "vehclClntNm"));

    let v_odrNo = ds_results.getCellData(v_row, "odrNo");
    let v_cntrSeq = ds_results.getCellData(v_row, "cntrSeq");
    let v_vehclClntNo = ds_results.getCellData(v_row, "vehclClntNo");

    for (let j = 0; j < ds_results.getRowCount(); j++) {
        if (ds_results.getCellData(j, "vehclClntNo") != ""
            && v_row != j
            && v_odrNo == ds_results.getCellData(j, "odrNo")
            && v_cntrSeq == ds_results.getCellData(j, "cntrSeq")
            && v_vehclClntNo != ds_results.getCellData(j, "vehclClntNo")) {
            await $c.win.alert("같은 오더, 컨테이너에 운송단계를 각각 다른  협력업체로 지정하여 동시에 배차할 수 없습니다. \n 운송단계 배차한 후에 회수단계를 배차하여 주시기 바랍니다.");
            ds_results.setCellData(v_row, "vehclClntNo", "");
            ds_results.setCellData(v_row, "vehclClntNm", "");
            return false;
        }
        if (v_odrNo == ds_results.getCellData(j, "odrNo") && v_cntrSeq == ds_results.getCellData(j, "cntrSeq")) {
            ds_results.setCellData(j, "vehclClntNo", ds_transBP.getCellData(rowIndex, "vehclClntNo"));
            ds_results.setCellData(j, "vehclClntNm", ds_transBP.getCellData(rowIndex, "vehclClntNm"));
        }
    }

    if (preChecked) {
        chk_retrvStpYn.setValue("true");
        scwin.f_filter();
    }
};

scwin.ds_results_onrowpositionchange = function(rowIndex, oldRow) {
    let curPos = ds_results.getRowPosition();
    if (acb_qryClsCd.getValue() == "N") {
        if (ds_results.getCellData(curPos, "openYn") == "1") {
            $c.gus.cfDisableObjects([btn_Open]);
        } else {
            $c.gus.cfEnableObjects([btn_Open]);
        }
    }
};
